;(function(){
	function apply(){
		var root=document.getElementById("root");
		if(!root) return;
		var logo=document.querySelector("section .logo-glow");
		var hero=(logo&&logo.closest("section"))||document.querySelector("section.hero-gradient");
		if(!hero) return;
		hero.classList.add("vertical-hero");
		hero.classList.remove("hero-gradient");
		hero.querySelectorAll(".orange-gradient").forEach(function(el){el.classList.remove("orange-gradient")});
		var h1=hero.querySelector("h1");
		if(h1){
			h1.textContent="CARDÁPIO DIGITAL";
			h1.classList.remove("mb-6");
			h1.classList.add("mb-4");
		}
		if(!hero.querySelector('[data-injected-video="1"]')){
			var iframe=document.createElement("iframe");
			var videoId="ysz5S6PUM-U";
			iframe.src="https://www.youtube-nocookie.com/embed/"+videoId+"?autoplay=1&mute=1&controls=0&modestbranding=1&playsinline=1&rel=0&loop=1&playlist="+videoId;
			iframe.setAttribute("title","Apresentação do Cardápio Digital");
			iframe.setAttribute("loading","lazy");
			iframe.setAttribute("allow","autoplay; encrypted-media; picture-in-picture");
			iframe.setAttribute("data-injected-video","1");
			iframe.className="video-embed";
			if(h1&&h1.parentElement){
				h1.insertAdjacentElement("afterend",iframe);
			}else{
				hero.appendChild(iframe);
			}
		}
	}
	if(document.readyState==="complete"||document.readyState==="interactive"){
		setTimeout(apply,0);
	}else{
		document.addEventListener("DOMContentLoaded",apply);
	}
})();
